e decoded string */\n  rawlen = (numQuantums * 3) - padding;\n\n  /* Allocate our buffer including room for a null-terminator */\n  newstr = malloc(rawlen + 1);\n  if(!newstr)\n    return CURLE_OUT_OF_MEMORY;\n\n  pos = newstr;\n\n  memset(lookup, 0xff, sizeof(lookup));\n  memcpy(&lookup['+'], decodetable, sizeof(decodetable));\n  /* replaces\n  {\n    unsigned char c;\n    const unsigned char *p = (const unsigned char *)base64encdec;\n    for(c = 0; *p; c++, p++)\n      lookup[*p] = c;\n  }\n  */\n\n  /* Decode the complete quantums first */\n  for(i = 0; i < fullQuantums; i++) {\n    unsigned char val;\n    unsigned int x = 0;\n    int j;\n\n    for(j = 0; j < 4; j++) {\n      val = lookup[(unsigned char)*src++];\n      if(val == 0xff) /* bad symbol */\n        goto bad;\n      x = (x << 6) | val;\n    }\n    pos[2] = x & 0xff;\n    pos[1] = (x >> 8) & 0xff;\n    pos[0] = (x >> 16) & 0xff;\n    pos += 3;\n  }\n  if(padding) {\n    /* this means either 8 or 16 bits output */\n    unsigned char val;\n    unsigned int x = 0;\n    int j;\n    size_t padc = 0;\n    for(j = 0; j < 4; j++) {\n      if(*src == '=') {\n        x <<= 6;\n        src++;\n        if(++padc > padding)\n          /* this is a badly placed '=' symbol! */\n          goto bad;\n      }\n      else {\n        val = lookup[(unsigned char)*src++];\n        if(val == 0xff) /* bad symbol */\n          goto bad;\n        x = (x << 6) | val;\n      }\n    }\n    if(padding == 1)\n      pos[1] = (x >> 8) & 0xff;\n    pos[0] = (x >> 16) & 0xff;\n    pos += 3 - padding;\n  }\n\n  /* Zero terminate */\n  *pos = '\\0';\n\n  /* Return the decoded data */\n  *outptr = newstr;\n  *outlen = rawlen;\n\n  return CURLE_OK;\nbad:\n  free(newstr);\n  return CURLE_BAD_CONTENT_ENCODING;\n}\n\nstatic CURLcode base64_encode(const char *table64,\n                              const char *inputbuff, size_t insize,\n                              char **outptr, size_t *outlen)\n{\n  char *output;\n  char *base64data;\n  const unsigned char *in = (unsigned char *)inputbuff;\n  const char *padstr = &table64[64];    /* Point to padding string. */\n\n  *outptr = NULL;\n  *outlen = 0;\n\n  if(!insize)\n    insize = strlen(inputbuff);\n\n#if SIZEOF_SIZE_T == 4\n  if(insize > UINT_MAX/4)\n    return CURLE_OUT_OF_MEMORY;\n#endif\n\n  base64data = output = malloc((insize + 2) / 3 * 4 + 1);\n  if(!output)\n    return CURLE_OUT_OF_MEMORY;\n\n  while(insize >= 3) {\n    *output++ = table64[ in[0] >> 2 ];\n    *output++ = table64[ ((in[0] & 0x03) << 4) | (in[1] >> 4) ];\n    *output++ = table64[ ((in[1] & 0x0F) << 2) | ((in[2] & 0xC0) >> 6) ];\n    *output++ = table64[ in[2] & 0x3F ];\n    insize -= 3;\n    in += 3;\n  }\n  if(insize) {\n    /* this is only one or two bytes now */\n    *output++ = table64[ in[0] >> 2 ];\n    if(insize == 1) {\n      *output++ = table64[ ((in[0] & 0x03) << 4) ];\n      if(*padstr) {\n        *output++ = *padstr;\n        *output++ = *padstr;\n      }\n    }\n    else {\n      /* insize == 2 */\n      *output++ = table64[ ((in[0] & 0x03) << 4) | ((in[1] & 0xF0) >> 4) ];\n      *output++ = table64[ ((in[1] & 0x0F) << 2) ];\n      if(*padstr)\n        *output++ = *padstr;\n    }\n  }\n\n  /* Zero terminate */\n  *output = '\\0';\n\n  /* Return the pointer to the new data (allocated memory) */\n  *outptr = base64data;\n\n  /* Return the length of the new data */\n  *outlen = (size_t)(output - base64data);\n\n  return CURLE_OK;\n}\n\n/*\n * Curl_base64_encode()\n *\n * Given a pointer to an input buffer and an input size, encode it and\n * return a pointer in *outptr to a newly allocated memory area holding\n * encoded data. Size of encoded data is returned in variable pointed by\n * outlen.\n *\n * Input length of 0 indicates input buffer holds a NUL-terminated string.\n *\n * Returns CURLE_OK on success, otherwise specific error code. Function\n * output shall not be considered valid unless CURLE_OK is returned.\n *\n * @unittest: 1302\n */\nCURLcode Curl_base64_encode(const char *inputbuff, size_t insize,\n                            char **outptr, size_t *outlen)\n{\n  return base64_encode(base64encdec, inputbuff, insize, outptr, outlen);\n}\n\n/*\n * Curl_base64url_encode()\n *\n * Given a pointer to an input buffer and an input size, encode it and\n * return a pointer in *outptr to a newly allocated memory area holding\n * encoded data. Size of encoded data is returned in variable pointed by\n * outlen.\n *\n * Input length of 0 indicates input buffer holds a NUL-terminated string.\n *\n * Returns CURLE_OK on success, otherwise specific error code. Function\n * output shall not be considered valid unless CURLE_OK is returned.\n *\n * @unittest: 1302\n */\nCURLcode Curl_base64url_encode(const char *inputbuff, size_t insize,\n                               char **outptr, size_t *outlen)\n{\n  return base64_encode(base64url, inputbuff, insize, outptr, outlen);\n}\n\n#endif /* no users so disabled */\n", "numLines": 294, "startLine": 1, "totalLines": 294}}

